  "version": "0.9",
  "updateComponents": {
    "surfaceId": "hr-surface",
    "components": [
      {
        "id": "root",
        "component": "Column",
        "children": [
          "confirmation_header",
          "review_summary_card"
        ]
      },
      {
        "id": "confirmation_header",
        "component": "Text",
        "text": "✅ Submission Finalized",
