      },
      {
        "id": "ticket_key_text",
        "component": "Text",
        "text": "**Ticket Key:** HR-8235F",
        "variant": "body"
      },
      {
        "id": "summary_divider",
        "component": "Divider",
        "axis": "horizontal"
      },
      {
        "id": "employee_text",
