      },
      {
        "id": "effective_date_text",
        "component": "Text",
        "text": "Effective Date: May 25, 2026 (Not Backdated)"
      },
      {
        "id": "summary_divider_2",
        "component": "Divider",
        "axis": "horizontal"
      },
