{
  "version": "0.9",
  "updateDataModel": {
    "surfaceId": "hr-surface",
    "value": {
      "employee": {
        "id": "EMP1001",
        "name": "Alex Mercer",
        "currentJobTitle": "Senior Game Advisor",
        "currentJobCode": "SGA01",
        "currentHourlyRate": 16.50,
        "currentStore": "4550"
      },
      "intake": {
        "changeType": "Promotion",
        "newJobCode": "",
        "newJobTitle": "",
        "newHourlyRate": 0,
        "effectiveDate": "",
        "justification": ""
