          }
        ]
      },
      {
        "id": "continue_button",
        "component": "Button",
        "child": "continue_button_text",
        "variant": "primary",
        "action": {
          "event": {
            "name": "start_promotion_review",
            "context": {
              "jobCode": {
                "path": "/intake/newJobCode"
              },
              "newRate": {
                "path": "/intake/newHourlyRate"
              },
              "effectiveDate": {
                "path": "/intake/effectiveDate"
              }
            }
          }
        }
      },
      {
        "id": "continue_button_text",
        "component": "Text",
        "text": "Review Promotion & Check Policy"
      }
    ]
  }
}
</a2ui-json>

I have audited the proposed changes against corporate HR policies. We have found a critical violation that requires correction and a policy flag that requires a justification before submission.

<a2ui-json>
