Hello! I see you're looking to process a personnel change for **EMP1001**. I've successfully retrieved their current employment and compensation profile.

The employee is **Alex Mercer (EMP1001)**, currently a **Senior Game Advisor** at store **4550**, earning **$16.50 per hour**.

Since you mentioned a **Promotion**, please use the form below to specify the details of the proposed change.

<a2ui-json>
{
  "version": "0.9",
  "updateDataModel": {
    "surfaceId": "hr-surface",
    "value": {
      "employee": {
        "id": "EMP1001",
        "name": "Alex Mercer",
        "currentJobTitle": "Senior Game Advisor",
        "currentJobCode": "SGA01",
        "currentHourlyRate": 16.50,
        "currentStore": "4550"
      },
      "intake": {
        "changeType": "Promotion",
        "newJobCode": "",
        "newJobTitle": "",
        "newHourlyRate": 0,
        "effectiveDate": "",
        "justification": ""
      },
      "jobs": [
        {
          "label": "Assistant Store Leader (ASL01)",
          "value": "ASL01"
        },
        {
          "label": "Store Leader (SL01)",
          "value": "SL01"
        },
        {
          "label": "Senior Game Advisor (SGA01)",
          "value": "SGA01"
        },
        {
          "label": "Game Advisor (GA01)",
          "value": "GA01"
        }
      ]
    }
  },
  "updateComponents": {
    "surfaceId": "hr-surface",
    "components": [
      {
        "id": "root",
        "component": "Column",
        "children": [
          "employee_details_card",
          "promotion_card",
          "continue_button"
        ]
      },
      {
        "id": "employee_details_card",
        "component": "Card",
        "child": "employee_details_column"
      },
      {
        "id": "employee_details_column",
        "component": "Column",
        "children": [
          "employee_card_title",
          "detail_name",
          "detail_title",
          "detail_pay"
        ]
      },
      {
        "id": "employee_card_title",
        "component": "Text",
        "text": "Current Employee Profile",
        "variant": "h4"
      },
      {
        "id": "detail_name",
        "component": "Text",
        "text": "Name: ${/employee/name} (${/employee/id})"
      },
      {
        "id": "detail_title",
        "component": "Text",
        "text": "Role: ${/employee/currentJobTitle} (${/employee/currentJobCode}) - Store ${/employee/currentStore}"
      },
      {
        "id": "detail_pay",
        "component": "Text",
        "text": "Current Pay: ${formatCurrency(value:/employee/currentHourlyRate, currency:'USD')}/hr"
      },
      {
        "id": "promotion_card",
        "component": "Card",
        "child": "promotion_input_column"
      },
      {
        "id": "promotion_input_column",
        "component": "Column",
        "children": [
          "promotion_title",
          "job_options_choicepicker",
          "new_pay_textfield",
          "effective_date_input"
        ]
      },
      {
        "id": "promotion_title",
        "component": "Text",
        "text": "Proposed Promotion Details",
        "variant": "h4"
      },
      {
        "id": "job_options_choicepicker",
        "component": "ChoicePicker",
        "label": "Select New Job Title",
        "options": {
          "componentId": "job_option_item",
          "path": "/jobs"
        },
        "value": {
          "path": "/intake/newJobCode"
        },
        "variant": "mutuallyExclusive",
        "displayStyle": "chips",
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/intake/newJobCode"
                }
              }
            },
            "message": "A new job title is required for a promotion."
          }
        ]
      },
      {
        "id": "job_option_item",
        "component": "ChoicePicker",
        "label": "${/label}",
        "value": "${/value}"
      },
      {
        "id": "new_pay_textfield",
        "component": "TextField",
        "label": "Proposed Hourly Pay Rate (USD)",
        "value": {
          "path": "/intake/newHourlyRate"
        },
        "variant": "number",
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/intake/newHourlyRate"
                }
              }
            },
            "message": "Proposed hourly rate is required."
          },
          {
            "condition": {
              "call": "numeric",
              "args": {
                "value": {
                  "path": "/intake/newHourlyRate"
                },
                "min": 0.01
              }
            },
            "message": "Hourly rate must be greater than $0.00."
          }
        ]
      },
      {
        "id": "effective_date_input",
        "component": "DateTimeInput",
        "label": "Effective Date",
        "value": {
          "path": "/intake/effectiveDate"
        },
        "enableDate": true,
        "checks": [
          {
            "condition": {
              "call": "required",
              "args": {
                "value": {
                  "path": "/intake/effectiveDate"
                }
              }
            },
            "message": "An effective date is required."
          }
        ]
      },
      {
        "id": "continue_button",
        "component": "Button",
        "child": "continue_button_text",
        "variant": "primary",
        "action": {
          "event": {
            "name": "start_promotion_review",
            "context": {
              "jobCode": {
                "path": "/intake/newJobCode"
              },
              "newRate": {
                "path": "/intake/newHourlyRate"
              },
              "effectiveDate": {
                "path": "/intake/effectiveDate"
              }
            }
          }
        }
      },
      {
        "id": "continue_button_text",
        "component": "Text",
        "text": "Review Promotion & Check Policy"
      }
    ]
  }
}
